examples.original_ir:
define i32 @test(ptr %p, i32 %x) {
  %v = load i32, ptr %p, !range !0
  %c = icmp eq i32 %x, 0
  %sel = select i1 %c, i32 %v, i32 %x
  ret i32 %sel
}

!0 = !{i32 0, i32 2}

examples.optimized_ir:
declare i32 @llvm.umax.i32(i32, i32)

define i32 @test(ptr %p, i32 %x) {
  %v = load i32, ptr %p, !range !0
  %sel = call i32 @llvm.umax.i32(i32 %v, i32 %x)
  ret i32 %sel
}

!0 = !{i32 0, i32 2}
